var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"하아……! 하아……! 하아……!","JPN":"はあ……はあ……はあ……！","ENG":"*Huff*... *Huff*... *Huff*...","TWN":"呼呼……呼呼……呼……！"},"stage":{"bg":"LABORATORY_03","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"실장님! 괜찮아요?!","JPN":"室長！　大丈夫ですか？","ENG":"Chief! Are you okay?!","TWN":"室長！你沒事吧？！"},"stage":{"bg":"LABORATORY_03","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L5_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"죽을 것 같지만……. 당장은 괜찮다고 해 둘게요.","JPN":"かなりまずい状態ではありますが……今のところは大丈夫だと言っておきます。","ENG":"Not really... But I’ll say that I am for now.","TWN":"雖然快死掉了……現在就先當我沒事吧！"},"stage":{"bg":"LABORATORY_03","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"부축해 드리겠습니다. 일어나세요, 실장님.","JPN":"さあ、手を。私が支えます、室長。","ENG":"Here, take my hand, Chief.","TWN":"室長，我來扶你起來。"},"stage":{"bg":"LABORATORY_03","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L7_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"고맙네요……. 배신자 딱지는 이제 떼도 될까요?","JPN":"ありがとうございます。裏切り者のレッテルはもう剥がしてもいいでしょうか？","ENG":"Thanks... Now, may I stop being called a traitor?","TWN":"謝謝……我現在可以撕掉叛徒的標籤了嗎？"},"stage":{"bg":"LABORATORY_03","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L8_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"리더가 판단할 문제이지만 정신을 잃은 상태라서요. 무사히 돌아가면 그 때 얘기하죠.","JPN":"リーダーが判断すべき問題ですが、気を失った状態ですので。\\n無事に帰ったらその時話しましょう。","ENG":"That’s for Leader to decide, but she’s kind of unconscious right now. We’ll talk about it once we’re out of here.","TWN":"這必須由老大來判斷，但她現在尚未清醒。等安全回到公司後再說吧。"},"stage":{"bg":"LABORATORY_03","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L9_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"지금은 한가하게 수다 떨 때가 아니니까요.","JPN":"今はのんびりおしゃべりをしている場合ではありませんので。","ENG":"Right now, there are other matters to attend to.","TWN":"現在還不是悠哉聊天的時候。"},"stage":{"bg":"LABORATORY_03","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L13_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"큭…… 불여시 같은 것……!","JPN":"くぅ……ずる賢いやつめ……！","ENG":"Krr... You vixen...!","TWN":"哼……臭丫頭……！"},"stage":{"bg":"LABORATORY_03","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_HATE"},"R":{"char_id":"JIA_ALPHA_NULL_FAKE","face":"UNIT_SERIOUS2"}}}},{"id":"L14_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"내가 카운터란 게 처음으로 고마운 순간이었어. 일반인이면 뼛가루도 안 남았을 테니까.","JPN":"私がカウンターであることに初めて感謝した瞬間だったわ。\\n一般人なら骨すら残っていなかった。","ENG":"This is the first time I’m glad that I’m a Counter. A normal person would’ve died from that attack.","TWN":"我還是第一次覺得還好她是制裁者，否則要是普通人的話，應該早就屍骨無存吧？"},"stage":{"bg":"LABORATORY_03","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JIA_ALPHA_NULL_FAKE","face":"UNIT_SERIOUS2"}}}},{"id":"L15_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"체크메이트까지는…… 한 수 모자랐지만 말이지.","JPN":"チェックメイトまでは……一手及ばなかったけどね。","ENG":"Guess you were one move off from a checkmate.","TWN":"雖然離將軍……還差一步。"},"stage":{"bg":"LABORATORY_03","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JIA_ALPHA_NULL_FAKE","face":"UNIT_SERIOUS2"}}}},{"id":"L17_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"쿨럭……!","JPN":"コホッ……！","ENG":"*Cough*","TWN":"咳咳……！"},"stage":{"bg":"LABORATORY_03","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"이제 포기하세요, 바이오닉스 대표.","JPN":"もう観念してください、バイオニクス代表。","ENG":"Surrender yourself, CEO of Bionics.","TWN":"仿生代表，收手吧！"},"stage":{"bg":"LABORATORY_03","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"그 장치 없이는…… 아가씨에게 더 이상 암시를 걸 수 없는 것 아닌가요?","JPN":"その装置が無ければ……お嬢様にこれ以上暗示をかけられないのでは？","ENG":"Without that... You can no longer control Miss Jia.","TWN":"沒有那個裝置……你就無法再對小姐下令吧？"},"stage":{"bg":"LABORATORY_03","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"그래. 하지만 너희들이 가진 패도 전부 바닥난 것 같은데.","JPN":"そうね。でも、あんたたちが持っている手札も底をついたようだけど。","ENG":"True, but I believe you’ve also showed me your hand too, no?","TWN":"話是沒錯，不過你們牌都已經出了吧？"},"stage":{"bg":"LABORATORY_03","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"JIA_ALPHA_NULL_FAKE","face":"UNIT_SERIOUS2"}}}},{"id":"L25_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LABORATORY_03","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"원래 계획은 지아가 직접 너희를 전부 죽이게 만드는 거였지만……","JPN":"元の計画だと、ユイちゃんの手であんたたちを皆殺しにする予定だったけど……","ENG":"I was originally going to make Jia kill all of you...","TWN":"雖然照原本的計畫，是要讓小佳親手殺光你們……"},"stage":{"bg":"LABORATORY_03","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JIA_ALPHA_NULL_FAKE","face":"UNIT_SERIOUS2"}}}},{"id":"L30_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"어쩔 수 없지. 나도 이번 대국에 전부를 걸었거든.","JPN":"仕方ないわね。私も今回の対局に全てを賭けたもの。","ENG":"But, you know, I'm all in on this as well.","TWN":"不過沒辦法，畢竟我也是賭上我的一切。"},"stage":{"bg":"LABORATORY_03","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"JIA_ALPHA_NULL_FAKE","face":"UNIT_SERIOUS2"}}}},{"id":"L44_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"이것들은 실험관 바깥에선 유통기한도 짧고 생산 단가까지 비싼 결함투성이야.","JPN":"こいつらは実験室の外では使用期限も短いし、生産単価も高い欠陥だらけ。","ENG":"These things don’t last long outside of their vats, are expensive to make, and are riddled with flaws.","TWN":"這些是效期短，而且製造成本又高的瑕疵品。"},"stage":{"bg":"LABORATORY_03","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"JIA_ALPHA_NULL_FAKE","face":"UNIT_SERIOUS2"}}}},{"id":"L45_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"이런 식의 물량전은 내 취향이 아니지만…… 인정해 주지.","JPN":"こんな物量作戦は私の好みではないけど……認めてあげるわ。","ENG":"I’m not one to play the numbers game, but... I’ll admit.","TWN":"雖然我不是很喜歡以多欺少……但承認吧！"},"stage":{"bg":"LABORATORY_03","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JIA_ALPHA_NULL_FAKE","face":"UNIT_SERIOUS2"}}}},{"id":"L46_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"지금은 승부의 취향을 따질 때가 아니라는 걸.","JPN":"今は勝負を好みに合わせる余裕がないということをね。","ENG":"This isn’t a time to be picky about which strategy I should use.","TWN":"現在不是講究輸贏手段的時候！"},"stage":{"bg":"LABORATORY_03","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"JIA_ALPHA_NULL_FAKE","face":"UNIT_SERIOUS2"}}}},{"id":"L48_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"총력전인가…….","JPN":"総力戦か……","ENG":"So it’s come to this...","TWN":"是要全部一起上嗎……"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"다들, 각오 단단히 하세요!","JPN":"皆さん、備えてください！","ENG":"Everyone, look sharp!","TWN":"大家，做好心理準備！"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"narration","speaker":null,"text":{"KOREA":"돌이켜 보면, 할아버님께선 늘 혼자셨다.","JPN":"振り返ってみれば、お祖父様はいつも一人だった。","ENG":"Looking back, Grandfather was always alone.","TWN":"回想起來，爺爺總是自己一個人。"},"stage":{"bg":"WHITE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"narration","speaker":null,"text":{"KOREA":"할아버님께 쉽게 말을 붙이는 사람도 없었고.","JPN":"お祖父様に気軽に話しかける人もいなかったし、","ENG":"No one really chatted with him.","TWN":"沒有人敢跟爺爺對話，"},"stage":{"bg":"WHITE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"narration","speaker":null,"text":{"KOREA":"할아버님도 다른 사람에게 말을 거는 일이 없었다.","JPN":"ご自身から話かけることもなかった。","ENG":"And he didn’t start conversations with others too.","TWN":"爺爺也不會主動找人說話。"},"stage":{"bg":"WHITE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"narration","speaker":null,"text":{"KOREA":"……할아버님께선, 늘 혼자였다.","JPN":"……お祖父様は、いつも一人だった。","ENG":"He was always alone.","TWN":"……爺爺總是自己一個人。"},"stage":{"bg":"WHITE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"narration","speaker":null,"text":{"KOREA":"그 모습이 너무나 쓸쓸해 보였던 나머지…….","JPN":"その姿があまりにも寂しそうに見えて……","ENG":"One day, I decided to surprise him with a gift...","TWN":"爺爺看起來實在太寂寞……"},"stage":{"bg":"WHITE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"narration","speaker":null,"text":{"KOREA":"하루는 할아버님께서 깜짝 놀랄 만한 선물을 드리기로 마음먹었다.","JPN":"ある日、お祖父様がびっくりするようなプレゼントをあげようと思いついた。","ENG":"After seeing how lonely he looked.","TWN":"某一天我打算要送爺爺一個驚喜。"},"stage":{"bg":"WHITE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CEO_NPC_ALPHA_NULL","text":{"KOREA":"아, 아들아……. 안 돼, 어떻게, 어떻게……!","JPN":"む、息子よ……ダメだ、なんてことだ……！","ENG":"N... no my boy ... this can't be…!","TWN":"我…我的兒子……不可以，怎麼會……！"},"stage":{"bg":"LAB","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CEO_NPC_ALPHA_NULL","text":{"KOREA":"새아가! 새아가는 어디 있니!","JPN":"嫁は、あの子はどこにいる！？","ENG":"Anyone...! Anyone have seen Shin family?","TWN":"媳婦！我的媳婦呢！"},"stage":{"bg":"LAB","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CEO_NPC_ALPHA_NULL","text":{"KOREA":"이런 걸, 이런 걸 바란 게 아니었는데……. 이런 건 아니었어……. 이런 건…….","JPN":"こんなことを、こんなことを望んだわけではない……\\nこんなはずではない……こんな……","ENG":"This… This was not meant to be…","TWN":"這…這不是我要的……不是這樣……不是……"},"stage":{"bg":"LAB","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JIA_CHILD_ALPHA_NULL","text":{"KOREA":"……할아버님.","JPN":"……お祖父様。","ENG":"...Grandfather.","TWN":"……爺爺。"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_CHILD_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL"},{"id":"L21_1","type":"dialog","speaker":"CEO_NPC_ALPHA_NULL","text":{"KOREA":"F 타입……. 아니, 지, 지아야……. 그게 무슨 꼴이니?","JPN":"Fタイプ……いや、ユ、ユイ……その格好は？","ENG":"Type-F... I-I mean, Jia... What happened to you?","TWN":"F型……不是，小佳……你那是怎麼回事？"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_CHILD_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JIA_CHILD_ALPHA_NULL","text":{"KOREA":"네? 아, 이 날개요?","JPN":"はい？　あ、この翅ですか？","ENG":"Huh? Oh, these wings?","TWN":"嗯？這雙翅膀嗎？"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_CHILD_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JIA_CHILD_ALPHA_NULL","text":{"KOREA":"할아버님 보여드리려고 펼쳤어요. 반짝거려서 예쁘죠, 할아버님?","JPN":"お祖父様にお見せしようと広げてみました。\\nキラキラして綺麗でしょう、お祖父様？","ENG":"I wanted you to see them. Aren’t they pretty how they sparkle, Grandfather?","TWN":"爺爺你看我的翅膀，亮亮的很漂亮吧？"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_CHILD_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CEO_NPC_ALPHA_NULL","text":{"KOREA":"마, 말도 안 돼……. 그 지도는 참고만 했을 뿐인데, 어떻게…….","JPN":"あ、あり得ない……あの地図は参考にしただけなのに、どうやって……","ENG":"I-impossible... I just used that map as reference... But how...?","TWN":"這…這怎麼可能……那個圖譜只是用來參考的而已，怎麼會……"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_CHILD_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CEO_NPC_ALPHA_NULL","text":{"KOREA":"설마…… 연구원들이 서로 싸우던 이유가……!?","JPN":"まさか……研究員たちが争っていた理由は……！？","ENG":"Is this... what the researchers were fighting over...?","TWN":"難道……研究員互毆的原因是……？！"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_CHILD_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"JIA_CHILD_ALPHA_NULL","text":{"KOREA":"할아버님, 왜 그러세요?","JPN":"お祖父様、どうしたのですか？","ENG":"What’s wrong, Grandfather?","TWN":"爺爺，你怎麼不說話？"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_CHILD_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JIA_CHILD_ALPHA_NULL","text":{"KOREA":"아, 맞다. 제가 이 날개로 할아버님이 원하는 건 뭐든 이루어 드릴게요.","JPN":"あ、そうだ。私がこの翅でお祖父様が願うことを何でも叶えてあげます。","ENG":"Oh, right. I’ll grant you anything you wish with these wings.","TWN":"對了，爺爺，我可以用這雙翅膀，替爺爺達成所有願望喔～"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_CHILD_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"JIA_CHILD_ALPHA_NULL","text":{"KOREA":"다른 분들에게는 이미 전부…….","JPN":"他の方々の願いはもう全部……","ENG":"I’ve already granted everyone else’s...","TWN":"其他人的願望我已經全部……"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_CHILD_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CEO_NPC_ALPHA_NULL","text":{"KOREA":"안 돼!! 절대 안 된다!!","JPN":"ダメだ！　それは絶対にダメだ！！","ENG":"NO!!! Absolutely not!!","TWN":"不可以！絕對不可以！！"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_CHILD_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"JIA_CHILD_ALPHA_NULL","text":{"KOREA":"네? 왜요?","JPN":"はい？　どうしてですか？","ENG":"Huh? Why not?","TWN":"為什麼？"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_CHILD_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CEO_NPC_ALPHA_NULL","text":{"KOREA":"그 날개를 펼치면 안 돼. 쓰면 쓸수록 널 점점 사람에서 멀어지게 만들 거다.","JPN":"その翅を広げてはならないのだ！\\n使えば使うほど、お前を『人』からどんどん遠ざけてしまうぞ！","ENG":"You must not use your wings. The more you use them, you will drift further away from humanity.","TWN":"你不可以展開那雙翅膀，這樣會讓你離人類越來越遠！"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_CHILD_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"JIA_CHILD_ALPHA_NULL","text":{"KOREA":"하지만…… 다들 좋아했는걸요?","JPN":"でも……みんな喜んでいましたよ？","ENG":"But... Everyone else likes it...","TWN":"可是……大家都很開心呢？"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_CHILD_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"CEO_NPC_ALPHA_NULL","text":{"KOREA":"지아야…….","JPN":"ユイ……","ENG":"Jia...","TWN":"小佳……"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_CHILD_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"CEO_NPC_ALPHA_NULL","text":{"KOREA":"……지아야, 보이니?","JPN":"……ユイ、見えるか？","ENG":"Jia... Do you see it?","TWN":"……小佳，你有看到嗎？"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CEO_NPC_ALPHA_NULL","text":{"KOREA":"인간은……. 이렇게 쉽게 상처 입는 나약한 종이란다.","JPN":"人間は……いとも簡単に傷ついてしまう、弱い生き物だ。","ENG":"Us humans... We are fragile beings.","TWN":"人類……就是如此軟弱無能的族類。"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CEO_NPC_ALPHA_NULL","text":{"KOREA":"그래서 상처를 입는 게 두려운 나머지, 자신과 다른 존재를 구별하고 솎아내려 해.","JPN":"だから傷つくことを恐れるあまり、自分とは異なる存在を区別し、排除しようとする。","ENG":"For fear of getting hurt, we try to differentiate ourselves from others unlike us.","TWN":"所以害怕受傷之餘，還會排擠和自己不同的種類。"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"JIA_CHILD_ALPHA_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"CEO_NPC_ALPHA_NULL","text":{"KOREA":"지아야, 네가 가진 힘은 사람들을 위해 쓰여야 한단다. 할애비 말, 무슨 뜻인지 알지?","JPN":"ユイ、お前が持つ力は人々のために使われるべきだ。\\n私の言葉がどういう意味か、わかるね？","ENG":"Jia, you must use your powers for humanity. Do you understand your grandpa?","TWN":"小佳，你的能力必須用來幫助人，你有聽懂爺爺的意思吧？"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"JIA_CHILD_ALPHA_NULL","text":{"KOREA":"네. 아빠도 말씀하셨어요. 밖에 나가서 모두를 행복하게 만들어 주면, 친구도 많이 사귈 수 있을 거라고요.","JPN":"はい。お父様もおっしゃいました。外に出てみんなを幸せにしてあげれば、\\nお友達もたくさん作れるそうです。","ENG":"Yes. Father told me that if I make everyone in the world happy, I'll make a lot of friends.","TWN":"懂，爺爺有說，等我出去後，只要讓大家幸福，就可以交到很多朋友。"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"CEO_NPC_ALPHA_NULL","text":{"KOREA":"그래…… 그렇지…… 착하구나, 지아야. 참 착해. ","JPN":"そうか……そうだな……いい子だ、ユイ。本当にいい子だ。","ENG":"Good... You’re a good girl, Jia.","TWN":"對……沒錯……小佳，真乖～"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"CEO_NPC_ALPHA_NULL","text":{"KOREA":"하지만 <color=#ffd34c>그건</color>…… 너를 두렵고 배척해야 할 존재로 만들 거란다.","JPN":"だが、<color=#ffd34c>それ</color>は……\\nお前を恐るべき存在、排斥すべき存在に変えてしまうだろう。","ENG":"But <color=#ffd34c>those</color>... are what will make people fear and alienate you.","TWN":"可是，<color=#ffd34c>那個</color>……會讓人家害怕你，甚至是排擠你。"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"JIA_CHILD_ALPHA_NULL","text":{"KOREA":"그러면…… 저는 어떻게 해야 돼요, 할아버님?","JPN":"それでは……私はどうすればいいのですか、お祖父様？","ENG":"Then... What am I supposed to do, Grandfather?","TWN":"那……爺爺，小佳該怎麼辦呢？"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"CEO_NPC_ALPHA_NULL","text":{"KOREA":"요정이 아니라, 사람으로서 살아가야지. ","JPN":"妖精ではなく、人として生きていかねばならない。","ENG":"You must live as a human being, not as a fairy.","TWN":"你不能當精靈，你要用人類的身分活下去，"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"CEO_NPC_ALPHA_NULL","text":{"KOREA":"……옛날 이야기에서 요정들이 두고 간 아이들이 그랬듯이.","JPN":"……おとぎ話に出てくる、妖精が置いていった子どもたちがそうしたように。","ENG":"Just like the children left behind by the fairies in the old tales...","TWN":"……就像以前的故事裡，精靈們留下的孩子那樣。"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"CEO_NPC_ALPHA_NULL","text":{"KOREA":"그러니 <color=#ffd34c>더 나은 세상을 위해</color>…….","JPN":"だから、<color=#ffd34c>より良い世界のために</color>……","ENG":"Therefore, <color=#ffd34c>for a better world</color>...","TWN":"所以，<color=#ffd34c>為了更好的未來</color>……"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_CHILD_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"CEO_NPC_ALPHA_NULL","text":{"KOREA":"……전부 잊어 버려라.","JPN":"……すべて忘れなさい。","ENG":"...forget everything.","TWN":"……這些事你全都忘了吧。"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_CHILD_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"JIA_CHILD_ALPHA_NULL","text":{"KOREA":"……네, 할아버님. 명심할게요.","JPN":"……はい、お祖父様。肝に銘じます。","ENG":"Yes, Grandfather. I’ll take your word to heart.","TWN":"……是，爺爺，我知道了。"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_CHILD_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"CEO_NPC_ALPHA_NULL","text":{"KOREA":"그래, 지아야. 어떤 일이 있더라도……. 다시는 그 날개를 펼쳐서는 안 된다.","JPN":"そうだ、ユイ。どんなことがあっても……二度とその翅を広げてはならない。","ENG":"No matter what, Jia... You must never use your wings.","TWN":"很好，小佳，無論發生什麼事……都不可以使用你的翅膀！"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_CHILD_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"CEO_NPC_ALPHA_NULL","text":{"KOREA":"내 말, 무슨 뜻인지 알지?","JPN":"私の言葉がどういう意味か、わかるね？","ENG":"Do you understand?","TWN":"你有聽懂我的意思吧？"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_CHILD_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"정신이 좀 들어, 신지아?","JPN":"気が付いた、ヒメノ・ユイ？","ENG":"Jia, are you awake?","TWN":"沈佳，你醒一醒？"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L11_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"고모님…….","JPN":"叔母様……","ENG":"Auntie...","TWN":"姑姑……"},"stage":{"bg":"LABORATORY_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"날 상대로 블러핑을 쓰다니 너도 안 본 사이 많이 닳아빠졌구나. 한 방 먹었어.","JPN":"私を相手にブラフィングを使うなんて、見ない間にあんたもずいぶん\\nやり手になったじゃない。一手食らっちゃったわ。","ENG":"You got me. I never thought you’d bluff against me.","TWN":"竟然敢和我玩花招，這麼久不見，你也變得奸詐不少嘛！被你擺了一道！"},"stage":{"bg":"LABORATORY_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L15_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"그런데 어쩌지? 이번 대국은 내가 이긴 거 같은데?","JPN":"でも、どうしよう？　今回の対局は私の勝ちみたいよ？","ENG":"But I’m sorry to tell you that I won this round.","TWN":"可是怎麼辦呢？這局棋好像是我贏了？"},"stage":{"bg":"LABORATORY_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"준……!! 정신차려! 준!!","JPN":"ジュン……しっかりして、ジュン！！","ENG":"Jun...!! Wake up! JUN!!","TWN":"朱恩……！！你醒醒！朱恩！！"},"stage":{"bg":"LABORATORY_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"}}},"sfx":"FX_CUTSCEN_BATTLEFIELD"},{"id":"L18_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"전열이 무너지면 안 돼요!! 새롬 양이 대신 선봉에 서 주세요!!","JPN":"戦列を崩してはいけません！！　アサネさんが代わりに前に出てください！！","ENG":"Maintain positions!! Saerom, take point!!","TWN":"保持隊形！！你去代替芷倫站在前鋒的位置！！"},"stage":{"bg":"LABORATORY_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L19_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"실장님, 이게 마지막 탄창이에요!","JPN":"室長、これが最後の弾倉です！","ENG":"Chief, this is the last of my ammo!","TWN":"室長，這是最後的彈匣了！"},"stage":{"bg":"LABORATORY_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L20_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"칫……! 아가씨만 확보할 수 있었어도 이런 불리한 싸움은……!","JPN":"まずい……！　お嬢様さえ確保できれば、こんな不利な戦いなんて……！","ENG":"Tch...! This fight would be a lot easier if we had secured Miss Jia...!","TWN":"嘖……！要是有小姐在，戰況也不會對我們如此不利……！"},"stage":{"bg":"LABORATORY_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L22_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"여러분…….","JPN":"皆さん……","ENG":"Everyone...","TWN":"大家……"},"stage":{"bg":"LABORATORY_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"너라면 알겠지. 내가 원한다면 언제든 저 머저리들을 처리할 수 있다는 걸.","JPN":"あんたならわかるでしょ。私が望むならいつでもあの間抜けどもを\\n始末できるってことを。","ENG":"You know just as well as I do that I can destroy them at will.","TWN":"你應該很清楚，只要我想，隨時都可以把他們處理掉！"},"stage":{"bg":"LABORATORY_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"그러니 너에게 마지막으로 선택의 기회를 줄게.","JPN":"だから、あんたに最後のチャンスを与えるわ。","ENG":"So, I’ll give you one last chance, Jia.","TWN":"我要給你最後一次選擇的機會。"},"stage":{"bg":"LABORATORY_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"……어떤 기회죠?","JPN":"……どんなチャンスですか？","ENG":"What kind of chance...?","TWN":"……什麼機會？"},"stage":{"bg":"LABORATORY_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L29_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"저것들을 살리고 싶다면, 나를 따라와.","JPN":"あいつらを助けたいなら、私についてきなさい。","ENG":"If you want them to keep breathing, come with me.","TWN":"想救他們的話，你就跟我走。"},"stage":{"bg":"LABORATORY_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"그게 네 인생의 최후의 선택이 되는 거야.","JPN":"それがあんたの人生で最後の選択になるわ。","ENG":"And that will be the last choice you’ll ever make.","TWN":"這是你人生中最後一次做選擇。"},"stage":{"bg":"LABORATORY_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"물론 반항하지 못하게 뇌 세척은 해야겠지만……. 죽는 것보단 낫지 않겠어?","JPN":"もちろん反抗できないように脳の洗浄は必要だけど……\\n死ぬよりはマシじゃない？","ENG":"Of course, I’ll have to brainwash you to never disobey me again... But that’s better than dying, isn’t it?","TWN":"當然我會替你洗腦，以免你反抗……但總比死來得好吧？"},"stage":{"bg":"LABORATORY_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"그건…….","JPN":"それは……","ENG":"That’s...","TWN":"我……"},"stage":{"bg":"LABORATORY_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L35_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"너무 고민하지 마.","JPN":"あまり悩まないで。","ENG":"Don’t think too hard about it.","TWN":"沒什麼好煩惱的啦～"},"stage":{"bg":"LABORATORY_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L36_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"어차피 명령하는 사람이 아버지에서 나로 바뀌는 것뿐이잖아?","JPN":"どうせ命令する人が父さんから私に変わるだけでしょ？","ENG":"Think of it as just replacing Father with me.","TWN":"不過就是下令的人從爸換成我而已，不是嗎？"},"stage":{"bg":"LABORATORY_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L37_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"넌 그냥 시키는 대로 얌전히 따르기만 하면 돼.","JPN":"あなたは言われたとおり、大人しく従えばいいのよ。","ENG":"All you need to do is obey my every will.","TWN":"你只需要乖乖照做就好。"},"stage":{"bg":"LABORATORY_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L39_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"여태까지 그래왔던 것처럼.","JPN":"今までのようにね。","ENG":"Just as you've always done.","TWN":"就跟你一直以來一樣。"},"stage":{"bg":"LABORATORY_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LABORATORY_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"다른 사람의 말은 결국 자네가 살면서 참고할 이정표지, 목적지가 아니야.","JPN":"他人の言うことは、君が生きていく中で参考できる道しるべにはなるが、\\n目的地にはなれないんだ。","ENG":"What I'm trying to say is that what others say is a reference point in your life, not your final destination.","TWN":"其他人說的話，不能成為你的終點或目的地。"},"stage":{"bg":"CAFE","bgm":"THMEA_SAD_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L42_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"목적지를 정하는 건 자네 자신의 마음에 달렸지.","JPN":"目的地を決めるのは君の心次第ってことだよ。","ENG":"Whichever direction you choose to go is entirely up to your heart.","TWN":"只有你的心能夠決定你的目的地！"},"stage":{"bg":"CAFE","bgm":"THMEA_SAD_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"마음…….","JPN":"私の心……","ENG":"My heart...","TWN":"我的心……"},"stage":{"bg":"CAFE","bgm":"THMEA_SAD_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"그렇지만 사장님, 전 여태까지 할아버님 말씀대로만 해 왔는데…….","JPN":"でも社長、私はこれまでお祖父様の言うとおりに生きてきたのに……","ENG":"Th-then... I’ve lived my life according to Grandfather’s words all this time...","TWN":"可是老闆，我一直以來都是按著爺爺的話而活……"},"stage":{"bg":"CAFE","bgm":"THMEA_SAD_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"이제 와서 스스로 뭔가를 선택할 수 있을까요?","JPN":"今さら自分で何かを決めることができるのでしょうか？","ENG":"Will I still be able to make choices by myself?","TWN":"現在我還能夠自己做選擇嗎？"},"stage":{"bg":"CAFE","bgm":"THMEA_SAD_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"아무렴! 물론이고 말고!","JPN":"ああ、もちろんだとも！","ENG":"Of course you can!","TWN":"那還用說！這是當然的！"},"stage":{"bg":"CAFE","bgm":"THMEA_SAD_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"걱정 말게, 지아 양. 나는 자네가 잘할 거라고 믿고 있어.","JPN":"心配はいらないぞ、ユイ君。私は君ならできると信じている。","ENG":"Don’t worry, Jia. I believe you’ll do great.","TWN":"沒事的，沈佳！我相信你可以的！"},"stage":{"bg":"CAFE","bgm":"THMEA_SAD_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"후후……. 고마워요. 사장님.","JPN":"フフッ……ありがとうございます、社長。","ENG":"He he... Thank you, sir.","TWN":"呵呵……謝謝老闆。"},"stage":{"bg":"LABORATORY_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"지아는 잘할 거예요. 사장님이 믿어 주셨으니까.","JPN":"ユイはできます。社長が信じてくれましたから。","ENG":"Jia will do great. You believe in me.","TWN":"小佳可以的，因為有老闆相信我。"},"stage":{"bg":"LABORATORY_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"웃어……? 지금 이 상황이 웃겨?","JPN":"笑ってる……？　この状況が面白いの？","ENG":"You laugh...? You think this is funny?","TWN":"笑什麼……？有什麼好笑的？"},"stage":{"bg":"LABORATORY_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"고모님, 전 이미 오래 전에 마음을 정했어요.","JPN":"叔母様、私はずっと前から心を決めました。","ENG":"Auntie, I’ve made up my mind a long time ago.","TWN":"姑姑，我很久以前就已經做好決定了。"},"stage":{"bg":"LABORATORY_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"저는 고모님을 쓰러트릴 거예요.","JPN":"私は叔母様を倒します。","ENG":"I’m going to defeat you.","TWN":"那就是我要在這裡，"},"stage":{"bg":"LABORATORY_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"바로 여기서.","JPN":"今ここで。","ENG":"Here, and now.","TWN":"打倒姑姑！"},"stage":{"bg":"LABORATORY_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"……아주 끝까지 날 얕잡아 보는구나, 이 역겨운 괴물 계집애.","JPN":"……最後の最後まで私を舐めやがって。この忌々しい化け物が。","ENG":"You still underestimate me until the very end, you monster.","TWN":"……看來你這個令人作噁的怪物，還是沒把我放眼裡。"},"stage":{"bg":"LABORATORY_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L8_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"날 쓰러트려? 어떻게?","JPN":"私を倒す？　どうやって？","ENG":"Defeat me? Are you sure?","TWN":"想打倒我？怎麼做？"},"stage":{"bg":"LABORATORY_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"체크메이트야! 이 상황에서 날 어떻게 한다고 저 머저리들이 무사할 수 있을 것 같아?!","JPN":"チェックメイトよ！　この状況であいつらが無事で済むとでも？","ENG":"It’s checkmate! Do you really think defeating me will change what happens to your idiot friends?!","TWN":"將軍！你敢動我一根寒毛的話，你以為他們會沒事嗎？！"},"stage":{"bg":"LABORATORY_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"너한테 선택지 따위는 없어! 닥치고 패배를 받아들이라고!","JPN":"あんたに選択肢なんて無いわ！　黙って敗北を受け入れなさい！","ENG":"You don’t have a choice in this! Admit your defeat!","TWN":"你沒有選擇的餘地！閉上你的嘴，承認失敗吧！"},"stage":{"bg":"LABORATORY_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L12_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"그건 제 마음에 들지 않는 선택지네요.","JPN":"それは私にとって気に入らない選択肢ですね。","ENG":"I’m afraid that won’t work with me.","TWN":"這個選擇不是我想要的！"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"그래서 결정했어요. 제 마음에 드는 선택지를 만들기로.","JPN":"だから決めました。自分のお気に入りの選択肢を作ると。","ENG":"I’ve decided... to make my own choice.","TWN":"我決定要選擇我真正想要的！"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"너, 그게 무슨……!","JPN":"あんた、何を……！","ENG":"W-what...?!","TWN":"你在說什麼……！"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":null,"text":{"KOREA":"……죄송해요, 할아버님.","JPN":"……申し訳ございません、お祖父様。","ENG":"...Forgive me, Grandfather.","TWN":"……爺爺對不起。"},"stage":{"bg":"WHITE","bgm":"THEMA_CA_JIA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ALPHA_CA_JIA_TRAILER_1"},{"id":"L18_1","type":"dialog","speaker":null,"text":{"KOREA":"할아버님께서는 저를 위해 그 날개를 접어두라고 하셨지만…….","JPN":"お祖父様は私のために、その翅を畳んでおきなさいとおっしゃいましたが……","ENG":"I know you told me to hide my wings for my own sake...","TWN":"雖然爺爺希望我收起翅膀……"},"stage":{"bg":"WHITE","bgm":"THEMA_CA_JIA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ALPHA_CA_JIA_TRAILER_2"},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"저는 모두를 구하기 위해.","JPN":"私はみんなを救うために。","ENG":"But to save everyone...","TWN":"但為了救大家，"},"stage":{"bg":"WHITE","bgm":"THEMA_CA_JIA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ALPHA_CA_JIA_TRAILER_3"},{"id":"L20_1","type":"dialog","speaker":null,"text":{"KOREA":"……그리고 더 나은 세상을 위해.","JPN":"……そして、より良い世界のために。","ENG":"and for a better world...","TWN":"……也為了更好的未來，"},"stage":{"bg":"WHITE","bgm":"THEMA_CA_JIA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ALPHA_CA_JIA_TRAILER_4"},{"id":"L21_1","type":"dialog","speaker":null,"text":{"KOREA":"쓸 수 있는 카드는 모두 쓰겠어요.","JPN":"使えるカードはすべて切らせていただきます。","ENG":"I have to use everything I’ve got.","TWN":"我會用盡所有的方法。"},"stage":{"bg":"WHITE","bgm":"THEMA_CA_JIA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ALPHA_CA_JIA_TRAILER_5"},{"id":"L24_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"어? 갑자기 뭐지……? 빛?","JPN":"うん？　急に何なの……？　光？","ENG":"Huh? Where’s that light coming from?","TWN":"嗯？這是怎樣……？有光？"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_CA_JIA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"이, 이거 봐! 오빠! 나 혼자 스포트라이트를 받고 있어!","JPN":"こ、これを見て、お兄ちゃん！　私一人でスポットライトを浴びてるよ！","ENG":"C-come look at this! Gabriel! I’m in the limelight!","TWN":"哥哥你看！聚光燈打在我身上欸！"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_CA_JIA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_TADA"},{"id":"L33_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"으음……? 내 검이 무지개빛으로 빛나다니?","JPN":"うむ……？　私の剣が虹色に輝いている？","ENG":"Hmm? My sword... It’s glowing in all seven colors?","TWN":"嗯……？是我的劍發出七彩之光嗎？"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_CA_JIA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"오오, 그런가! 이것이야말로 파사검의 진정한 형태……!","JPN":"おお、そうか！　これぞまさしく破邪剣の真の形……！","ENG":"Ooh, I see! This is the true form of Evil-fighting Greatsword...!","TWN":"原來如此！這才是破邪劍的真本事……！"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_CA_JIA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L48_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"아얏! 아야야! 뭐가 하늘에서 막 떨어져!?","JPN":"痛っ！　いたたた！　空から何か落ちてきた！？","ENG":"Ow! Ouch! There’s something falling from the sky.","TWN":"哇！欸欸欸！好像有東西從天而降欸？"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_CA_JIA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"이건……. 특수탄이야. 하지만 어디서…….","JPN":"これは……特殊弾ですね。しかしどこから……","ENG":"They’re... special bullets. But where are they coming from...?","TWN":"這是……特殊彈，可是是從哪裡……"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_CA_JIA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L1_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"……아가씨?","JPN":"……お嬢様？","ENG":"Miss Jia?","TWN":"……小姐？"},"stage":{"bg":"LABORATORY_03","bgm":"THEMA_CA_JIA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"저 날개는……?","JPN":"あの翅は……？","ENG":"Those wings...","TWN":"翅膀……？"},"stage":{"bg":"ALPHA_06","bgm":"THEMA_CA_JIA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"설마, 유전자 구조 설계 과정에서 삽입된 암시를 스스로 깨 버렸다고……?","JPN":"まさか、遺伝子構造設計の過程で入れた暗示を自ら破った……？","ENG":"You couldn’t have... You freed yourself from the code embedded in your DNA...?","TWN":"難道是她自己解除掉基因組成設計過程中插入的暗號……？"},"stage":{"bg":"ALPHA_06","bgm":"THEMA_CA_JIA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"말도 안 돼……!! 이미 의지로 어쩔 수 있는 영역이 아니잖아!!","JPN":"あり得ない……！！　意志でどうにかできる領域じゃないわ！！","ENG":"Impossible...!! That can’t be done by pure will!!","TWN":"這怎麼可能……！！這不是靠意志力就可以辦到的吧！"},"stage":{"bg":"ALPHA_06","bgm":"THEMA_CA_JIA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"대체 무슨 짓을 한 거야, 신지아!!","JPN":"いったい何をしたのよ、ヒメノ・ユイ！！","ENG":"What did you do, Shin Jia?!!","TWN":"沈佳，你到底做了什麼！！"},"stage":{"bg":"ALPHA_06","bgm":"THEMA_CA_JIA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"<color=#ffd34c>사용해도 된다</color>고 하는 할아버님 목소리를 들었다고 상상했거든요.","JPN":"<color=#ffd34c>使ってもいい</color>というお祖父様の声を想像しました。","ENG":"I imagined that Grandfather’s voice told me that <color=#ffd34c>I’m allowed to use them</color>.","TWN":"我只是想像聽到爺爺跟我說，<color=#ffd34c>可以使用</color>。"},"stage":{"bg":"ALPHA_06","bgm":"THEMA_CA_JIA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ALPHA_CA_JIA_TRAILER_6"},{"id":"L8_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"고모님이 정확한 성문을 들려 주신 덕분에 상상하기 어렵지 않았어요.","JPN":"叔母様が正確な声紋を聞かせてくれたおかげで、想像しやすかったです。","ENG":"Since you spoke in his voice, the rest wasn’t that hard.","TWN":"多虧姑姑提供爺爺的聲音，所以想像起來不會太困難。"},"stage":{"bg":"ALPHA_06","bgm":"THEMA_CA_JIA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ALPHA_CA_JIA_TRAILER_7"},{"id":"L9_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"뭐……?","JPN":"なんですって……？","ENG":"What...?","TWN":"什麼……？"},"stage":{"bg":"ALPHA_06","bgm":"THEMA_CA_JIA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"그딴 농담 집어치워!! 상상한다고 풀릴 정도의 암시일 것 같아, 그게?!","JPN":"ふざけた冗談はやめなさい！！　\\nそれが想像で解ける程度の暗示だと思ってるの！？","ENG":"Enough joking around!! You think that it can be broken just by imagining it?!","TWN":"你在跟我開什麼玩笑！！光靠想像就可以解除暗號？"},"stage":{"bg":"ALPHA_06","bgm":"THEMA_CA_JIA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JIA_ALPHA_NEXT_NULL","text":{"KOREA":"진심을 담아서 상상하면 돼요.","JPN":"心を込めて想像すればできます。","ENG":"I just have to imagine it with all my heart.","TWN":"只要發自內心去想像就可以辦得到。"},"stage":{"bg":"ALPHA_06","bgm":"THEMA_CA_JIA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ALPHA_CA_JIA_TRAILER_8"},{"id":"L12_1","type":"dialog","speaker":"JIA_ALPHA_NEXT_NULL","text":{"KOREA":"어때요, 참 쉽죠?","JPN":"どうですか？　本当に簡単でしょう？","ENG":"Easy, isn’t it?","TWN":"很簡單對吧？"},"stage":{"bg":"ALPHA_06","bgm":"THEMA_CA_JIA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ALPHA_CA_JIA_TRAILER_9"},{"id":"L13_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"하…….","JPN":"ハ……","ENG":"Ha…","TWN":"哈……"},"stage":{"bg":"ALPHA_06","bgm":"THEMA_CA_JIA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"하하……! 아하하하하하……!","JPN":"ハハハッ……！　アハハハハハハハッ……！","ENG":"Haha...! Ahahahahaha...!","TWN":"哈哈……！哈哈哈哈哈……！"},"stage":{"bg":"ALPHA_06","bgm":"THEMA_CA_JIA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"그래……! 그렇게 나와야지! 역시 네 잘난 면상은 흔적도 없이 뭉개 버리는 게 맞아!!","JPN":"そうね……！　そうこなくちゃ！\\nやっぱりあんたのその偉そうなツラは跡形もなく潰してやるべきだわ！！","ENG":"Yes...! There you go! I knew I was going to crush that pretty face of yours!!","TWN":"很好……！這樣才對嘛！果然要打爛你那張囂張的臉才可以！！"},"stage":{"bg":"ALPHA_06","bgm":"THEMA_CA_JIA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L16_1","type":"dialog","speaker":"JIA_ALPHA_NEXT_NULL","text":{"KOREA":"글쎄요. 그건 상상하시는 만큼 쉽지 않을 것 같네요, 고모님.","JPN":"そうですか。それは想像するほど簡単ではないと思いますよ、叔母様。","ENG":"Well, I don’t think it’ll be as easy as you think, Auntie.","TWN":"這我不確定，可能沒有想像中容易，姑姑。"},"stage":{"bg":"ALPHA_06","bgm":"THEMA_CA_JIA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ALPHA_CA_JIA_TRAILER_10"},{"id":"L17_1","type":"dialog","speaker":"JIA_ALPHA_NEXT_NULL","text":{"KOREA":"지금은 저도…… 최선이라는 걸 다해 볼 테니까요!","JPN":"今回は私も……最善を尽くしてみますから！","ENG":"Because I will also... do my best to stop you!","TWN":"因為現在……我也決定要盡我最大的努力！"},"stage":{"bg":"ALPHA_06","bgm":"THEMA_CA_JIA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL","voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ALPHA_CA_JIA_TRAILER_11"}]`);export{e as default};